package store

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"strconv"
	"time"

	"github.com/redis/go-redis/v9"
	"github.com/volcano-sh/agentcube/pkg/common/types"
)

var ErrNotFound = errors.New("store: not found")

type redisStore struct {
	cli                  *redis.Client
	sessionPrefix        string
	expiryIndexKey       string
	lastActivityIndexKey string
}

func newRedisStore() (*redisStore, error) {
	redisAddr := os.Getenv("REDIS_ADDR")
	if redisAddr == "" {
		return nil, errors.New("REDIS_ADDR is required")
	}

	redisPassword := os.Getenv("REDIS_PASSWORD")
	passwordRequired := os.Getenv("REDIS_PASSWORD_REQUIRED")
	if redisPassword == "" && !stringsEqualIgnoreCase(passwordRequired, "false") {
		return nil, errors.New("REDIS_PASSWORD is required")
	}

	opts := &redis.Options{
		Addr:     redisAddr,
		Password: redisPassword,
	}

	cli := redis.NewClient(opts)
	return &redisStore{
		cli:                  cli,
		sessionPrefix:        "session:",
		expiryIndexKey:       "session:expiry",
		lastActivityIndexKey: "session:last_activity",
	}, nil
}

func stringsEqualIgnoreCase(s, target string) bool {
	if len(s) != len(target) {
		return false
	}
	for i := 0; i < len(s); i++ {
		c1 := s[i]
		c2 := target[i]
		if c1 >= 'A' && c1 <= 'Z' {
			c1 += 32
		}
		if c2 >= 'A' && c2 <= 'Z' {
			c2 += 32
		}
		if c1 != c2 {
			return false
		}
	}
	return true
}

func (s *redisStore) Ping(ctx context.Context) error {
	result, err := s.cli.Ping(ctx).Result()
	if err != nil {
		return err
	}
	if result != "PONG" {
		return fmt.Errorf("unexpected ping response: %s", result)
	}
	return nil
}

func (s *redisStore) sessionKey(sessionID string) string {
	return s.sessionPrefix + sessionID
}

func (s *redisStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := s.sessionKey(sessionID)
	data, err := s.cli.Get(ctx, key).Bytes()
	if err != nil {
		if errors.Is(err, redis.Nil) {
			return nil, ErrNotFound
		}
		return nil, err
	}
	var info types.SandboxInfo
	if err := json.Unmarshal(data, &info); err != nil {
		return nil, err
	}
	return &info, nil
}

func (s *redisStore) StoreSandbox(ctx context.Context, sandboxStore *types.SandboxInfo) error {
	if sandboxStore == nil {
		return errors.New("sandbox is nil")
	}
	if sandboxStore.ExpiresAt.IsZero() {
		return errors.New("ExpiresAt is required")
	}

	key := s.sessionKey(sandboxStore.SessionID)
	data, err := json.Marshal(sandboxStore)
	if err != nil {
		return err
	}

	pipe := s.cli.Pipeline()
	pipe.SetNX(ctx, key, data, 0)
	pipe.ZAdd(ctx, s.expiryIndexKey, redis.Z{
		Score:  float64(sandboxStore.ExpiresAt.Unix()),
		Member: sandboxStore.SessionID,
	})
	pipe.ZAdd(ctx, s.lastActivityIndexKey, redis.Z{
		Score:  float64(time.Now().Unix()),
		Member: sandboxStore.SessionID,
	})

	_, err = pipe.Exec(ctx)
	return err
}

func (s *redisStore) UpdateSandbox(ctx context.Context, sandboxStore *types.SandboxInfo) error {
	key := s.sessionKey(sandboxStore.SessionID)
	data, err := json.Marshal(sandboxStore)
	if err != nil {
		return err
	}

	result, err := s.cli.SetXX(ctx, key, data, 0).Result()
	if err != nil {
		return err
	}
	if !result {
		return errors.New("key not exists")
	}
	return nil
}

func (s *redisStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := s.sessionKey(sessionID)

	pipe := s.cli.Pipeline()
	pipe.Del(ctx, key)
	pipe.ZRem(ctx, s.expiryIndexKey, sessionID)
	pipe.ZRem(ctx, s.lastActivityIndexKey, sessionID)

	_, err := pipe.Exec(ctx)
	return err
}

func (s *redisStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}

	sessionIDs, err := s.cli.ZRangeByScore(ctx, s.expiryIndexKey, &redis.ZRangeBy{
		Min:   "-inf",
		Max:   strconv.FormatInt(before.Unix(), 10),
		Count: limit,
	}).Result()
	if err != nil {
		return nil, err
	}

	return s.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (s *redisStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}

	sessionIDs, err := s.cli.ZRangeByScore(ctx, s.lastActivityIndexKey, &redis.ZRangeBy{
		Min:   "-inf",
		Max:   strconv.FormatInt(before.Unix(), 10),
		Count: limit,
	}).Result()
	if err != nil {
		return nil, err
	}

	return s.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (s *redisStore) loadSandboxesBySessionIDs(ctx context.Context, sessionIDs []string) ([]*types.SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return nil, nil
	}

	keys := make([]string, len(sessionIDs))
	for i, id := range sessionIDs {
		keys[i] = s.sessionKey(id)
	}

	results, err := s.cli.MGet(ctx, keys...).Result()
	if err != nil {
		return nil, err
	}

	var sandboxes []*types.SandboxInfo
	for i, result := range results {
		if result == nil {
			continue
		}
		str, ok := result.(string)
		if !ok {
			continue
		}
		var info types.SandboxInfo
		if err := json.Unmarshal([]byte(str), &info); err != nil {
			continue
		}
		sandboxes = append(sandboxes, &info)
		_ = i
	}

	return sandboxes, nil
}

func (s *redisStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return errors.New("session id is empty")
	}

	key := s.sessionKey(sessionID)
	exists, err := s.cli.Exists(ctx, key).Result()
	if err != nil {
		return err
	}
	if exists == 0 {
		return ErrNotFound
	}

	if at.IsZero() {
		at = time.Now()
	}

	return s.cli.ZAdd(ctx, s.lastActivityIndexKey, redis.Z{
		Score:  float64(at.Unix()),
		Member: sessionID,
	}).Err()
}

func (s *redisStore) Close() error {
	return s.cli.Close()
}

package store

import (
	"context"
