		}
	})
	return provider
}

func initStore() error {
	storeType := os.Getenv("STORE_TYPE")
	if storeType == "" {
		storeType = redisStoreType
	}

	switch strings.ToLower(storeType) {
	case redisStoreType:
		s, err := newRedisStore()
		if err != nil {
			return err
		}
		provider = s
	case valkeyStoreType:
		s, err := newValkeyStore()
		if err != nil {
			return err
		}
		provider = s
	default:
		return errInvalidStoreType(storeType)
	}
	return nil
}

