package workloadmanager

import (
	"context"
	"errors"
	"net/http"
	"strings"
	"time"

	"github.com/gin-gonic/gin"
	authenticationv1 "k8s.io/api/authentication/v1"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/client-go/kubernetes"
)

type TokenCache struct {
	entries map[string]*tokenEntry
	maxSize int
	ttl     time.Duration
}

type tokenEntry struct {
	username           string
	serviceAccountName string
	namespace          string
	lastAccess         time.Time
}

func NewTokenCache(maxSize int, ttl time.Duration) *TokenCache {
	return &TokenCache{
		entries: make(map[string]*tokenEntry),
		maxSize: maxSize,
		ttl:     ttl,
	}
}

func (tc *TokenCache) Get(token string) (*tokenEntry, bool) {
	entry, ok := tc.entries[token]
	if !ok {
		return nil, false
	}
	if time.Since(entry.lastAccess) > tc.ttl {
		delete(tc.entries, token)
		return nil, false
	}
	entry.lastAccess = time.Now()
	return entry, true
}

func (tc *TokenCache) Set(token string, username, saName, namespace string) {
	if len(tc.entries) >= tc.maxSize {
		for k, v := range tc.entries {
			if time.Since(v.lastAccess) > tc.ttl {
				delete(tc.entries, k)
			}
		}
	}
	tc.entries[token] = &tokenEntry{
		username:           username,
		serviceAccountName: saName,
		namespace:          namespace,
		lastAccess:         time.Now(),
	}
}

func (s *Server) authMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.JSON(http.StatusUnauthorized, ErrorResponse{Message: "Missing authorization header"})
			c.Abort()
			return
		}

		parts := strings.SplitN(authHeader, " ", 2)
		if len(parts) != 2 || parts[0] != "Bearer" {
			c.JSON(http.StatusUnauthorized, ErrorResponse{Message: "Invalid authorization header format"})
			c.Abort()
			return
		}

		token := parts[1]
		entry, ok := s.tokenCache.Get(token)
		if ok {
			c.Set(string(contextKeyUserToken), token)
			c.Set(string(contextKeyServiceAccount), entry.username)
			c.Set(string(contextKeyServiceAccountName), entry.serviceAccountName)
			c.Set(string(contextKeyNamespace), entry.namespace)
			c.Next()
			return
		}

		username, saName, namespace, err := s.validateServiceAccountToken(c.Request.Context(), token)
		if err != nil {
			c.JSON(http.StatusUnauthorized, ErrorResponse{Message: "Invalid token"})
			c.Abort()
			return
		}

		s.tokenCache.Set(token, username, saName, namespace)
		c.Set(string(contextKeyUserToken), token)
		c.Set(string(contextKeyServiceAccount), username)
		c.Set(string(contextKeyServiceAccountName), saName)
		c.Set(string(contextKeyNamespace), namespace)
		c.Next()
	}
}

func (s *Server) validateServiceAccountToken(ctx context.Context, token string) (username, saName, namespace string, err error) {
	if s.k8sClient == nil || s.k8sClient.clientset == nil {
		return "", "", "", errors.New("kubernetes client not initialized")
	}

	tr := &authenticationv1.TokenReview{
		Spec: authenticationv1.TokenReviewSpec{
			Token: token,
		},
	}

	result, err := s.k8sClient.clientset.AuthenticationV1().TokenReviews().Create(ctx, tr, metav1.CreateOptions{})
	if err != nil {
		return "", "", "", err
	}

	if !result.Status.Authenticated {
		return "", "", "", errors.New("token not authenticated")
	}

	username = result.Status.User.Username
	if strings.HasPrefix(username, "system:serviceaccount:") {
		parts := strings.Split(username, ":")
		if len(parts) >= 4 {
			namespace = parts[2]
			saName = parts[3]
		}
	}

	return username, saName, namespace, nil
}

type K8sClient struct {
	clientset         *kubernetes.Clientset
	dynamicClient     dynamic.Interface
	scheme            *runtime.Scheme
	baseConfig        *rest.Config
	clientCache       *ClientCache
	dynamicInformer   dynamicinformer.DynamicSharedInformerFactory
	informerFactory   informers.SharedInformerFactory
	podInformer       cache.SharedIndexInformer
	podLister         listersv1.PodLister
}

type ClientCache struct {
	clients map[string]dynamic.Interface
	mu      sync.RWMutex
}

func NewClientCache() *ClientCache {
	return &ClientCache{
		clients: make(map[string]dynamic.Interface),
	}
}

func (cc *ClientCache) GetOrCreate(namespace, saName string, config *rest.Config) (dynamic.Interface, error) {
	key := namespace + ":" + saName
	cc.mu.RLock()
	if client, ok := cc.clients[key]; ok {
		cc.mu.RUnlock()
		return client, nil
	}
	cc.mu.RUnlock()

	cc.mu.Lock()
	defer cc.mu.Unlock()
	if client, ok := cc.clients[key]; ok {
		return client, nil
	}

	client, err := dynamic.NewForConfig(config)
	if err != nil {
		return nil, err
	}
	cc.clients[key] = client
	return client, nil
}

