	"os/signal"
	"syscall"

	"github.com/volcano-sh/agentcube/pkg/workloadmanager"
	"golang.org/x/net/http2"
	"golang.org/x/net/http2/h2c"
)

func main() {
	port := flag.String("port", "8080", "API port")
	runtimeClassName := flag.String("runtime-class-name", "kuasar-vmm", "Runtime class name")
	enableTLS := flag.Bool("enable-tls", false, "Enable TLS")
	tlsCert := flag.String("tls-cert", "", "TLS certificate path")
	tlsKey := flag.String("tls-key", "", "TLS key path")
	enableAuth := flag.Bool("enable-auth", false, "Enable authentication")
	flag.Parse()

	cfg := &workloadmanager.Config{
		Port:             *port,
		RuntimeClassName: *runtimeClassName,
		EnableTLS:        *enableTLS,
		TLSCert:          *tlsCert,
		TLSKey:           *tlsKey,
		EnableAuth:       *enableAuth,
	}

	server, err := workloadmanager.NewServer(cfg)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Failed to create server: %v\n", err)
		os.Exit(1)
	}

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)

	go func() {
		<-sigCh
		fmt.Println("Shutting down...")
		if err := server.Shutdown(ctx); err != nil {
			fmt.Fprintf(os.Stderr, "Shutdown error: %v\n", err)
		}
		cancel()
	}()

	h2s := &http2.Server{}
	addr := ":" + *port
	httpServer := &http.Server{
		Addr:    addr,
		Handler: h2c.NewHandler(server, h2s),
	}

	fmt.Printf("Starting workload manager on %s\n", addr)
	if *enableTLS {
		if *tlsCert == "" || *tlsKey == "" {
			fmt.Fprintln(os.Stderr, "TLS enabled but cert/key not provided")
			os.Exit(1)
		}
		if err := httpServer.ListenAndServeTLS(*tlsCert, *tlsKey); err != nil && err != http.ErrServerClosed {
			fmt.Fprintf(os.Stderr, "Server error: %v\n", err)
			os.Exit(1)
		}
	} else {
		if err := httpServer.ListenAndServe(); err != nil && err != http.ErrServerClosed {
			fmt.Fprintf(os.Stderr, "Server error: %v\n", err)
			os.Exit(1)
		}
	}
}

